// Mirrors React-template CustomIconWithText.jsx — custom-icon-with-text-01, 02

import type { ReactNode } from "react";

export interface CIWTItem {
  icon: ReactNode;
  number?: string;
  title: string;
  content: string;
}

interface Props {
  theme?: "custom-icon-with-text-01" | "custom-icon-with-text-02";
  data: CIWTItem[];
  grid?: string;
}

export default function CustomIconWithText({ theme = "custom-icon-with-text-01", data, grid }: Props) {
  if (theme === "custom-icon-with-text-02") {
    return (
      <div className="space-y-0">
        {data.map((item, i) => (
          <div key={i} className="ciwt-02">
            {item.number && <span className="ci-num">{item.number}</span>}
            <div className="ci-icon-box">{item.icon}</div>
            <div>
              <h5>{item.title}</h5>
              <p>{item.content}</p>
            </div>
          </div>
        ))}
      </div>
    );
  }

  const defaultGrid = grid || "grid-cols-1 sm:grid-cols-2 lg:grid-cols-4";
  return (
    <div className={`grid ${defaultGrid} gap-6`}>
      {data.map((item, i) => (
        <div key={i} className="ciwt-01">
          <div className="ci-icon">{item.icon}</div>
          <div className="ci-sep" />
          <h5>{item.title}</h5>
          <p>{item.content}</p>
        </div>
      ))}
    </div>
  );
}
