// Mirrors React-template ClientCarousel.jsx — auto-scrolling logo strip

import type { ClientItem } from "./Clients";

interface Props {
  data: ClientItem[];
}

export default function ClientCarousel({ data }: Props) {
  // Duplicate for seamless infinite loop
  const items = [...data, ...data];

  return (
    <div className="client-carousel">
      <div className="client-carousel-track">
        {items.map((c, i) => (
          <a key={i} href={c.link || "#"} className="cl-logo">
            <img src={c.img} alt="" />
          </a>
        ))}
      </div>
    </div>
  );
}
