// Mirrors React-template OverLineIconBox.jsx

import type { ReactNode } from "react";

export interface OverlineItem {
  icon: ReactNode;
  title: string;
  content: string;
}

interface Props {
  data: OverlineItem[];
  grid?: string;
}

export default function OverlineIconBox({ data, grid = "grid-cols-1 sm:grid-cols-2 lg:grid-cols-3" }: Props) {
  return (
    <div className={`grid ${grid} gap-6`}>
      {data.map((item, i) => (
        <div key={i} className="olib-item">
          <div className="olib-icon">{item.icon}</div>
          <h5>{item.title}</h5>
          <p>{item.content}</p>
        </div>
      ))}
    </div>
  );
}
