// Mirrors React-template SocialIcons.jsx — social-icon-style-01 to 12
import type { ReactNode } from "react";

export interface SocialIconItem {
  icon: ReactNode;
  link: string;
  label?: string;
  ariaLabel?: string;
}

interface Props {
  theme?: "social-icon-style-01" | "social-icon-style-02" | "social-icon-style-03" | "social-icon-style-04" |
          "social-icon-style-05" | "social-icon-style-06" | "social-icon-style-07" | "social-icon-style-08" |
          "social-icon-style-09" | "social-icon-style-10" | "social-icon-style-11" | "social-icon-style-12";
  data: SocialIconItem[];
  size?: "sm" | "md" | "lg";
}

const sizeMap = { sm: "w-7 h-7 text-xs", md: "w-9 h-9 text-sm", lg: "w-11 h-11 text-base" };

export default function SocialIcons({ theme = "social-icon-style-01", data, size = "md" }: Props) {
  const sz = sizeMap[size];
  const themeClass = theme.replace("social-icon-style-", "si-style-");
  const getLabel = (item: SocialIconItem) => item.ariaLabel || item.label || "Social link";

  // Style-09: icon + text label (width: auto)
  if (theme === "social-icon-style-09" || theme === "social-icon-style-11") {
    return (
      <div className={`social-icons ${themeClass}`}>
        {data.map((item, i) => (
          <a key={i} href={item.link} style={{ height: "36px" }} aria-label={getLabel(item)}>
            <span className="font-bold">{item.icon}</span>
            {theme === "social-icon-style-09" && <span>{item.label || getLabel(item)}</span>}
          </a>
        ))}
      </div>
    );
  }

  // Style-10: icon + label stacked (larger)
  if (theme === "social-icon-style-10") {
    return (
      <div className={`social-icons ${themeClass}`}>
        {data.map((item, i) => (
          <a key={i} href={item.link} aria-label={getLabel(item)}>
            <span style={{ fontSize: "1rem" }}>{item.icon}</span>
            <span>{item.label || getLabel(item)}</span>
          </a>
        ))}
      </div>
    );
  }

  return (
    <div className={`social-icons ${themeClass}`}>
      {data.map((item, i) => (
        <a key={i} href={item.link} className={sz} aria-label={getLabel(item)}>
          <span>{item.icon}</span>
        </a>
      ))}
    </div>
  );
}
