// Mirrors React-template RotateBox.jsx — 3D flip card on hover

import type { ReactNode } from "react";

export interface RotateBoxItem {
  img: string;
  title: string;
  subtitle?: string;
  icon?: ReactNode;
  content: string;
  btnTitle?: string;
  btnLink?: string;
  backBg?: string;
}

interface Props {
  data: RotateBoxItem[];
  grid?: string;
}

export default function RotateBox({ data, grid = "grid-cols-1 sm:grid-cols-2 lg:grid-cols-4" }: Props) {
  return (
    <div className={`grid ${grid} gap-6`}>
      {data.map((item, i) => (
        <div key={i} className="rotate-box">
          <div className="rotate-box-inner">
            {/* Front */}
            <div className="rotate-box-front">
              <img src={item.img} alt={item.title} />
              <div className="rb-overlay">
                <h5>{item.title}</h5>
                {item.subtitle && <div className="rb-sub">{item.subtitle}</div>}
              </div>
            </div>
            {/* Back */}
            <div
              className="rotate-box-back"
              style={{ background: item.backBg || "linear-gradient(135deg, var(--primary), var(--primary-dark))" }}
            >
              {item.icon && <div className="rb-icon text-white">{item.icon}</div>}
              <h5 className="text-white">{item.title}</h5>
              <p className="text-white/80">{item.content}</p>
              {item.btnTitle && (
                <a href={item.btnLink || "#"} className="btn btn-sm btn-fancy-white">
                  {item.btnTitle}
                </a>
              )}
            </div>
          </div>
        </div>
      ))}
    </div>
  );
}
