// Mirrors React-template InfoBanner — info-banner-style-01, 03, 05

export interface InfoBannerItem {
  img: string;
  badge?: string;
  title: string;
  content: string;
  link?: string;
  linkTitle?: string;
}

interface Props {
  theme?: "info-banner-style-01" | "info-banner-style-03" | "info-banner-style-05";
  data: InfoBannerItem[];
  grid?: string;
}

export default function InfoBanner({ theme = "info-banner-style-01", data, grid = "grid-cols-1 sm:grid-cols-2 lg:grid-cols-3" }: Props) {
  return (
    <div className={`grid ${grid} gap-6`}>
      {data.map((item, i) => {
        if (theme === "info-banner-style-03") return <Style03 key={i} item={item} />;
        if (theme === "info-banner-style-05") return <Style05 key={i} item={item} />;
        return <Style01 key={i} item={item} />;
      })}
    </div>
  );
}

function Style01({ item }: { item: InfoBannerItem }) {
  return (
    <div className="info-banner-01">
      <img src={item.img} alt={item.title} />
      {item.badge && <span className="ib-badge">{item.badge}</span>}
      <div className="ib-body">
        <h5>{item.title}</h5>
        <p>{item.content}</p>
        {item.link && (
          <a href={item.link} className="ib-link">
            {item.linkTitle || "Learn More"} →
          </a>
        )}
      </div>
    </div>
  );
}

function Style03({ item }: { item: InfoBannerItem }) {
  return (
    <div className="info-banner-03">
      <img src={item.img} alt={item.title} />
      <div className="ib-overlay" />
      <div className="ib-content">
        {item.badge && <div className="text-xs font-bold tracking-widest uppercase text-white/70 mb-2">{item.badge}</div>}
        <h5>{item.title}</h5>
        {item.link && (
          <a href={item.link} className="ib-link">
            {item.linkTitle || "Explore"} →
          </a>
        )}
      </div>
    </div>
  );
}

function Style05({ item }: { item: InfoBannerItem }) {
  return (
    <div className="info-banner-05">
      <div className="ib-img">
        <img src={item.img} alt={item.title} />
      </div>
      <div className="ib-body">
        {item.badge && <span className="ib-badge">{item.badge}</span>}
        <h5>{item.title}</h5>
        <p>{item.content}</p>
        {item.link && (
          <a href={item.link} className="ib-link">
            {item.linkTitle || "Learn More"} →
          </a>
        )}
      </div>
    </div>
  );
}
