// Mirrors React-template FancyTextBox.jsx — fancy-text-box-01 to 05

import type { ReactNode } from "react";

export interface FTBItem {
  icon?: ReactNode;
  img?: string;
  title: string;
  description?: string;
  link?: string;
}

interface Props {
  theme?: "fancy-text-box-01" | "fancy-text-box-02" | "fancy-text-box-03" | "fancy-text-box-04" | "fancy-text-box-05";
  data: FTBItem[];
  grid?: string;
}

export default function FancyTextBox({ theme = "fancy-text-box-01", data, grid = "grid-cols-1 sm:grid-cols-2 lg:grid-cols-3" }: Props) {
  return (
    <div className={`grid ${grid} gap-6`}>
      {data.map((item, i) => {
        if (theme === "fancy-text-box-02") return <Style02 key={i} item={item} />;
        if (theme === "fancy-text-box-03") return <Style03 key={i} item={item} />;
        if (theme === "fancy-text-box-04") return <Style04 key={i} item={item} />;
        if (theme === "fancy-text-box-05") return <Style05 key={i} item={item} />;
        return <Style01 key={i} item={item} />;
      })}
    </div>
  );
}

function Style01({ item }: { item: FTBItem }) {
  return (
    <div className="ftb-01 group">
      <div className="ftb-icon">{item.icon || "💡"}</div>
      <h5>{item.title}</h5>
      <div className="ftb-desc">{item.description}</div>
    </div>
  );
}

function Style02({ item }: { item: FTBItem }) {
  return (
    <div className="ftb-02">
      <div className="ftb-icon">{item.icon || "💡"}</div>
      <div>
        <h5>{item.title}</h5>
        {item.description && <p>{item.description}</p>}
      </div>
    </div>
  );
}

function Style03({ item }: { item: FTBItem }) {
  return (
    <div className="ftb-03">
      <div className="ftb-icon">{item.icon || "💡"}</div>
      <h5>{item.title}</h5>
      {item.description && <p>{item.description}</p>}
    </div>
  );
}

function Style04({ item }: { item: FTBItem }) {
  return (
    <div className="ftb-04">
      <div className="ftb-icon">{item.icon || "💡"}</div>
      <h5>{item.title}</h5>
      {item.description && <p>{item.description}</p>}
      {item.link && <a href={item.link} className="btn-link-fancy mt-3 text-xs inline-flex">Learn more</a>}
    </div>
  );
}

function Style05({ item }: { item: FTBItem }) {
  return (
    <div className="ftb-05">
      {item.img && <img src={item.img} alt={item.title} />}
      <div className="ftb-overlay" />
      <div className="ftb-content">
        <h5>{item.title}</h5>
        {item.description && <div className="ftb-desc">{item.description}</div>}
      </div>
    </div>
  );
}
