// Mirrors React-template TextBox.jsx — text-box-style-01, 02

export interface TextBoxItem {
  number?: string;
  title: string;
  content: string;
  link?: string;
}

interface Props {
  theme?: "text-box-style-01" | "text-box-style-02";
  data: TextBoxItem[];
  grid?: string;
}

export default function TextBox({ theme = "text-box-style-01", data, grid = "grid-cols-1 sm:grid-cols-2 lg:grid-cols-3" }: Props) {
  const cls = theme === "text-box-style-02" ? "text-box-02" : "text-box-01";
  return (
    <div className={`grid ${grid} gap-6`}>
      {data.map((item, i) => (
        <div key={i} className={cls}>
          {item.number && <span className="tb-num">{item.number}</span>}
          <h5>{item.title}</h5>
          <p>{item.content}</p>
          {item.link && (
            <a href={item.link} className="btn-link-fancy mt-4 inline-flex">
              Discover More →
            </a>
          )}
        </div>
      ))}
    </div>
  );
}
