// Mirrors React-template Buttons.jsx — all button style variants

import type { ReactNode } from "react";

interface Props {
  href?: string;
  onClick?: () => void;
  size?: "xs" | "sm" | "md" | "lg" | "xl";
  variant?: "fill-dark" | "fill-primary" | "outline" | "outline-white" | "white" | "gradient" | "link";
  icon?: ReactNode;
  iconPosition?: "before" | "after";
  children: ReactNode;
  className?: string;
}

const sizeMap = {
  xs: "btn-sm text-[0.65rem] px-4 py-1.5",
  sm: "btn-sm",
  md: "",
  lg: "btn-lg",
  xl: "btn-xl",
};

const variantMap = {
  "fill-dark":     "btn-fancy-dark",
  "fill-primary":  "btn-fancy-primary",
  "outline":       "btn-fancy-outline",
  "outline-white": "btn-fancy-outline-white",
  "white":         "btn-fancy-white",
  "gradient":      "btn-gradient",
  "link":          "btn-link-fancy",
};

export default function Buttons({ href = "#", onClick, size = "md", variant = "fill-primary", icon, iconPosition = "after", children, className = "" }: Props) {
  const cls = `btn ${sizeMap[size]} ${variantMap[variant]} ${className}`.trim();

  const content = (
    <>
      {icon && iconPosition === "before" && <span>{icon}</span>}
      {children}
      {icon && iconPosition === "after" && <span>{icon}</span>}
    </>
  );

  if (onClick) {
    return <button className={cls} onClick={onClick}>{content}</button>;
  }
  return <a href={href} className={cls}>{content}</a>;
}
