// Mirrors React-template Services.jsx — service-style-01 to 05
// Usage: <Services theme="service-style-01" data={...} grid="grid-cols-3" />

import type { ReactNode } from "react";

export interface ServiceItem {
  img?: string;
  icon?: ReactNode;
  title: string;
  content: string;
  link?: string;
  linkTitle?: string;
  btnName?: string;
  btnLink?: string;
}

interface Props {
  theme: "service-style-01" | "service-style-02" | "service-style-03" | "service-style-04" | "service-style-05" | "service-style-06";
  data: ServiceItem[];
  grid?: string;
}

export default function Services({ theme, data, grid = "grid-cols-1 sm:grid-cols-2 lg:grid-cols-3" }: Props) {
  return (
    <div className={`grid ${grid} gap-6`}>
      {data.map((item, i) => {
        if (theme === "service-style-01") return <Style01 key={i} item={item} />;
        if (theme === "service-style-02") return <Style02 key={i} item={item} />;
        if (theme === "service-style-03") return <Style03 key={i} item={item} />;
        if (theme === "service-style-04") return <Style04 key={i} item={item} />;
        if (theme === "service-style-05") return <Style05 key={i} item={item} />;
        if (theme === "service-style-06") return <Style06 key={i} item={item} num={String(i + 1).padStart(2, "0")} />;
        return null;
      })}
    </div>
  );
}

function Style01({ item }: { item: ServiceItem }) {
  return (
    <div className="service-01">
      <div className="s-img">
        {item.img && <img src={item.img} alt={item.title} />}
      </div>
      <div className="s-body">
        <span className="s-icon">→</span>
        <h5>{item.title}</h5>
        <p>{item.content}</p>
      </div>
    </div>
  );
}

function Style02({ item }: { item: ServiceItem }) {
  return (
    <div className="service-02">
      <div className="s-img">
        {item.img && <img src={item.img} alt={item.title} />}
      </div>
      <div className="s-body">
        <h5>{item.title}</h5>
        <p>{item.content}</p>
        {item.link && (
          <a href={item.link} className="s-link">
            {item.linkTitle || "More Info"} <span>→</span>
          </a>
        )}
      </div>
    </div>
  );
}

function Style03({ item }: { item: ServiceItem }) {
  return (
    <div className="service-03">
      {item.img && <img src={item.img} alt={item.title} />}
      <div className="s-overlay">
        <h5>{item.title}</h5>
      </div>
    </div>
  );
}

function Style04({ item }: { item: ServiceItem }) {
  return (
    <div className="service-04">
      {item.img && (
        <div className="s-img-box">
          <img src={item.img} alt={item.title} />
        </div>
      )}
      <div>
        <h5>{item.title}</h5>
        <p>{item.content}</p>
      </div>
    </div>
  );
}

function Style06({ item, num }: { item: ServiceItem; num: string }) {
  return (
    <div className="service-06">
      <div className="s-number">{num}</div>
      <div className="s-icon">{item.icon || "⚡"}</div>
      <h5>{item.title}</h5>
      <p>{item.content}</p>
    </div>
  );
}

function Style05({ item }: { item: ServiceItem }) {
  return (
    <div className="service-05">
      <div className="s-icon-box">{item.icon || "⚡"}</div>
      <h5>{item.title}</h5>
      <p>{item.content}</p>
      {item.link && (
        <a href={item.link} className="s-link">
          {item.linkTitle || "More Info"} →
        </a>
      )}
    </div>
  );
}
